38	Array<int64_t> BatchPagedAttentionPlan(TensorView float_workspace_buffer,
39	                                       TensorView int_workspace_buffer,
40	                                       TensorView page_locked_int_workspace_buffer,
41	                                       TensorView qo_indptr, TensorView kv_indptr,
42	                                       TensorView kv_len, int64_t batch_size, int64_t num_qo_heads,
43	                                       int64_t num_kv_heads, int64_t head_dim_o, bool causal) {
44	  size_t float_workspace_size_in_bytes =
45	      float_workspace_buffer.size(0) * get_element_size(float_workspace_buffer);
46	  size_t int_workspace_size_in_bytes =
47	      int_workspace_buffer.size(0) * get_element_size(int_workspace_buffer);
48	
49	  HolisticPlanInfo<2> plan_info;
50	
51	  ffi::CUDADeviceGuard device_guard(float_workspace_buffer.device().device_id);
52	  const cudaStream_t stream = get_stream(float_workspace_buffer.device());
53	
54	  cudaError_t status = TwoStageHolisticPlan<IdType>(
55	      float_workspace_buffer.data_ptr(), float_workspace_size_in_bytes,
56	      int_workspace_buffer.data_ptr(), page_locked_int_workspace_buffer.data_ptr(),
57	      int_workspace_size_in_bytes, plan_info, static_cast<IdType*>(qo_indptr.data_ptr()),
58	      static_cast<IdType*>(kv_indptr.data_ptr()), static_cast<IdType*>(kv_len.data_ptr()),
59	      batch_size, num_qo_heads, num_kv_heads, head_dim_o, causal, stream);
60	
61	  TVM_FFI_ICHECK(status == cudaSuccess)
62	      << "Failed to plan persistent paged attention, error: " << cudaGetErrorString(status);
63	
64	  return Array(plan_info.ToVector());
65	}
