67	void BatchPagedAttentionRun(TensorView float_workspace_buffer, TensorView int_workspace_buffer,
68	                            Array<int64_t> plan_info_vec, TensorView q, TensorView k_cache,
69	                            TensorView v_cache, TensorView kv_indices, TensorView o,
70	                            Optional<TensorView> maybe_lse, int64_t mask_mode_code,
71	                            int64_t layout_code, int64_t num_qo_heads, int64_t num_kv_heads,
72	                            int64_t page_size,
73	                            double v_scale,  // must use double due to pytorch binding
74	                            double sm_scale,
75	                            double logits_soft_cap ADDITIONAL_FUNC_PARAMS PROFILER_FUNC_PARAMS) {
76	  HolisticPlanInfo<2> plan_info;
77	  plan_info.FromVector(std::vector<int64_t>(plan_info_vec.begin(), plan_info_vec.end()));
78	
79	  void* float_buffer_ptr = float_workspace_buffer.data_ptr();
80	  void* int_buffer_ptr = int_workspace_buffer.data_ptr();
81	
82	  const MaskMode mask_mode = static_cast<MaskMode>(mask_mode_code);
83	
84	  // NOTE (Yilong): assume both q and o are NHD
85	  unsigned int q_stride_n = q.stride(0);
86	  unsigned int q_stride_h = q.stride(1);
87	
88	  // layout only constraint paged KV
89	  const QKVLayout kv_layout = static_cast<QKVLayout>(layout_code);
90	  unsigned int k_stride_page = k_cache.stride(0);
91	  unsigned int v_stride_page = v_cache.stride(0);
92	  unsigned int k_stride_n, k_stride_h, v_stride_n, v_stride_h;
93	  if (kv_layout == QKVLayout::kNHD) {
94	    k_stride_h = k_cache.stride(2);
95	    k_stride_n = k_cache.stride(1);
96	    v_stride_h = v_cache.stride(2);
97	    v_stride_n = v_cache.stride(1);
98	  } else {
99	    k_stride_h = k_cache.stride(1);
100	    k_stride_n = k_cache.stride(2);
101	    v_stride_h = v_cache.stride(1);
102	    v_stride_n = v_cache.stride(2);
103	  }
104	
105	  ffi::CUDADeviceGuard device_guard(q.device().device_id);
106	  const cudaStream_t stream = get_stream(q.device());
107	
108	  DISPATCH_context(
109	      DTypeQ, DTypeKV, DTypeO, IdType, MASK_MODE, HEAD_DIM_QK, HEAD_DIM_VO, POS_ENCODING_MODE,
110	      AttentionVariant, PersistentParams, [&] {
111	        PersistentParams params[2];
112	        IdType* len_kv_chunk =
113	            GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.len_kv_chunk_offset);
114	        for (int i = 0; i < 2; i++) {
115	          params[i].q = static_cast<DTypeQ*>(q.data_ptr());
116	          params[i].k = static_cast<DTypeKV*>(k_cache.data_ptr());
117	          params[i].v = static_cast<DTypeKV*>(v_cache.data_ptr());
118	
119	          params[i].q_indptr =
120	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.tasks[i].q_indptr_offset);
121	          params[i].kv_indptr =
122	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.tasks[i].kv_indptr_offset);
123	          params[i].partial_indptr = GetPtrFromBaseOffset<IdType>(
124	              int_buffer_ptr, plan_info.tasks[i].partial_indptr_offset);
125	          params[i].kv_indices = static_cast<int*>(kv_indices.data_ptr());
126	          params[i].q_len =
127	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.tasks[i].q_len_offset);
128	          params[i].kv_len =
129	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.tasks[i].kv_len_offset);
130	          params[i].q_start =
131	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.tasks[i].q_start_offset);
132	          params[i].kv_start =
133	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.tasks[i].kv_start_offset);
134	          params[i].kv_end =
135	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.tasks[i].kv_end_offset);
136	          params[i].kv_head_idx_arr =
137	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.tasks[i].kv_head_idx_offset);
138	          params[i].work_indptr =
139	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.tasks[i].work_indptr_offset);
140	          params[i].len_kv_chunk = len_kv_chunk + i;
141	
142	          params[i].final_o = static_cast<DTypeO*>(o.data_ptr());
143	          params[i].final_lse =
144	              maybe_lse.has_value() ? static_cast<float*>(maybe_lse.value().data_ptr()) : nullptr;
145	          params[i].partial_o =
146	              GetPtrFromBaseOffset<DTypeO>(float_buffer_ptr, plan_info.partial_o_offset);
147	          params[i].partial_lse =
148	              GetPtrFromBaseOffset<float>(float_buffer_ptr, plan_info.partial_lse_offset);
149	
150	          // for state reduction
151	          params[i].merge_indptr =
152	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.merge_indptr_offset);
153	          params[i].merge_o_indices =
154	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.merge_o_indices_offset);
155	          params[i].num_packed_qo_len =
156	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.num_qo_len_offset);
157	
158	          params[i].num_kv_heads = num_kv_heads;
159	          params[i].gqa_group_size = uint_fastdiv(num_qo_heads / num_kv_heads);
160	          params[i].page_size = uint_fastdiv(page_size);
161	
162	          params[i].q_stride_n = q_stride_n;
163	          params[i].q_stride_h = q_stride_h;
164	          params[i].k_stride_page = k_stride_page;
165	          params[i].k_stride_h = k_stride_h;
166	          params[i].k_stride_n = k_stride_n;
167	          params[i].v_stride_page = v_stride_page;
168	          params[i].v_stride_h = v_stride_h;
169	          params[i].v_stride_n = v_stride_n;
170	          params[i].k_sf_stride_page = 0;
171	          params[i].k_sf_stride_h = 0;
172	          params[i].k_sf_stride_n = 0;
173	          params[i].v_sf_stride_page = 0;
174	          params[i].v_sf_stride_h = 0;
175	          params[i].v_sf_stride_n = 0;
176	
177	          params[i].sm_scale = sm_scale;
178	          params[i].v_scale = v_scale;
179	          params[i].logits_soft_cap = logits_soft_cap;
180	          // NOTE(Wenxuan) directly using the additional_params_decl from generate_additional_params
181	          // will be problematic because of the params[i]
182	          ADDITIONAL_PARAMS_SETTER
183	          PROFILER_PARAMS_SETTER
184	        }
185	
186	        cudaError_t status = BatchPagedAttentionPersistent<128, 16, HEAD_DIM_QK, HEAD_DIM_VO,
187	                                                           MASK_MODE, AttentionVariant>(
188	            params[0], params[1], plan_info.num_blks_x, plan_info.num_blks_y, stream);
189	        TVM_FFI_ICHECK(status == cudaSuccess)
190	            << "Failed to run persistent paged attention, error: " << cudaGetErrorString(status);
191	        return true;
192	      });
193	}
