9	#include <flashinfer/profiler.cuh>
10	
11	using namespace flashinfer;
12	
13	#define ADDITIONAL_FUNC_PARAMS {{ additional_func_params }}
14	#define ADDITIONAL_PARAMS_SETTER {{ additional_params_setter }}
15	
16	#ifdef FLASHINFER_ENABLE_PROFILER
17	#define PROFILER_PARAMS_SETTER \
18	  params[i].profiler_buffer = static_cast<uint64_t*>(profiler_buffer.data_ptr());
19	#else
20	#define PROFILER_PARAMS_SETTER
21	#endif
22	
23	{{ variant_decl }}
24	
25	template <bool UseLogitsSoftCap>
26	struct StandardAttention : AttentionVariantBase {
27	  float sm_scale_log2;
28	  float soft_cap_pre_tanh_scale;
29	  static constexpr bool use_logits_soft_cap = UseLogitsSoftCap;
30	  PROFILER_CLOSURE_PARAMS_DECL
31	
32	  template <typename Params>
33	  __device__ __host__ StandardAttention(const Params& params, uint32_t batch_idx,
34	                                        uint8_t* smem_ptr) {
35	    if constexpr (UseLogitsSoftCap) {
36	      soft_cap_pre_tanh_scale = params.sm_scale * math::ptx_rcp(params.logits_soft_cap);
37	      sm_scale_log2 = math::log2e * params.logits_soft_cap;
38	    }else{
39	      sm_scale_log2 = params.sm_scale * math::log2e;
40	    }
41	  }
42	  REGISTER_LOGITS_TRANSFORM(params, logits, batch_idx, qo_idx, kv_idx, qo_head_idx, kv_head_idx, {
43	    if constexpr (UseLogitsSoftCap) {
44	      logits = float(math::tanh(logits * soft_cap_pre_tanh_scale));
45	    }
46	    return logits;
47	  })
48	};
49	
50	#define DISPATCH_context(DTypeQ, DTypeKV, DTypeO, IdType, MASK_MODE, HEAD_DIM_QK, HEAD_DIM_VO, POS_ENCODING_MODE, AttentionVariant, Params, ...) \
51	  DISPATCH_MASK_MODE(mask_mode, MASK_MODE, { \
52	    using AttentionVariant = {{ variant_name }}; \
53	    __VA_ARGS__(); \
54	  })
55	
56	using DTypeQ = {{ dtype_q }};
57	using DTypeKV = {{ dtype_kv }};
58	using DTypeO = {{ dtype_o }};
59	using IdType = {{ idtype }};
60	
61	constexpr int HEAD_DIM_QK = {{ head_dim_qk }};
62	constexpr int HEAD_DIM_VO = {{ head_dim_vo }};
63	constexpr auto POS_ENCODING_MODE = {{ pos_encoding_mode }};
64	
65	struct PersistentParams {
66	  using DTypeQ = DTypeQ;
67	  using DTypeKV = DTypeKV;
68	  using DTypeO = DTypeO;
69	  using IdType = IdType;
70	
71	  DTypeQ* q;
72	  DTypeKV* k;
73	  DTypeKV* v;
74	  DTypeO* o;
75	  DTypeO* partial_o;
76	  float* partial_lse;
77	  DTypeO* final_o;
78	  float* final_lse;
79	
80	  IdType* q_indptr;
81	  IdType* kv_indptr;
82	  IdType* partial_indptr;
83	  IdType* kv_indices;
84	  IdType* q_len;
85	  IdType* kv_len;
86	  IdType* q_start;
87	  IdType* kv_start;
88	  IdType* kv_end;
