645	cudaError_t BatchPagedAttentionPersistent(const Params params_1, const Params params_2,
646	                                          const uint32_t num_blks_x, const uint32_t num_blks_y,
647	                                          const cudaStream_t stream) {
648	  static_assert(HEAD_DIM_VO <= 256 && HEAD_DIM_QK <= 256,
649	                "BatchAttention (holistic persistent) kernel does not support "
650	                "head_dim > 256; use the FA2 prefill/decode path for large head dims.");
651	  using DTypeQ = typename Params::DTypeQ;
652	  using DTypeKV = typename Params::DTypeKV;
653	  using DTypeO = typename Params::DTypeO;
654	  using IdType = typename Params::IdType;
655	  constexpr uint32_t NUM_WARPS_Q_1 = get_num_warps_q(CTA_TILE_Q_1);
656	  constexpr uint32_t NUM_WARPS_KV_1 = get_num_warps_kv(CTA_TILE_Q_1);
657	  constexpr uint32_t NUM_MMA_Q_1 = get_num_mma_q(CTA_TILE_Q_1);
658	  constexpr uint32_t NUM_MMA_KV_1 = 4;
659	  constexpr uint32_t NUM_MMA_D_QK = HEAD_DIM_QK / 16;
660	  constexpr uint32_t NUM_MMA_D_VO = HEAD_DIM_VO / 16;
661	  using KTraits1 = KernelTraits<MASK_MODE, CTA_TILE_Q_1, NUM_MMA_Q_1, NUM_MMA_KV_1, NUM_MMA_D_QK,
662	                                NUM_MMA_D_VO, NUM_WARPS_Q_1, NUM_WARPS_KV_1, PosEncodingMode::kNone,
663	                                DTypeQ, DTypeKV, DTypeO, float, IdType, AttentionVariant>;
664	  constexpr uint32_t NUM_WARPS_Q_2 = get_num_warps_q(CTA_TILE_Q_2);
665	  constexpr uint32_t NUM_WARPS_KV_2 = get_num_warps_kv(CTA_TILE_Q_2);
666	  constexpr uint32_t NUM_MMA_Q_2 = get_num_mma_q(CTA_TILE_Q_2);
667	  constexpr uint32_t NUM_MMA_KV_2 = 2;
668	  using KTraits2 = KernelTraits<MASK_MODE, CTA_TILE_Q_2, NUM_MMA_Q_2, NUM_MMA_KV_2, NUM_MMA_D_QK,
669	                                NUM_MMA_D_VO, NUM_WARPS_Q_2, NUM_WARPS_KV_2, PosEncodingMode::kNone,
670	                                DTypeQ, DTypeKV, DTypeO, float, IdType, AttentionVariant>;
671	
672	  // Attention state reduction kernel
673	  constexpr uint32_t NUM_THREADS =
674	      KTraits1::NUM_THREADS > KTraits2::NUM_THREADS ? KTraits1::NUM_THREADS : KTraits2::NUM_THREADS;
675	  using ReductionKTraits =
676	      StateReductionKernelTraits<HEAD_DIM_VO, 4, NUM_THREADS, DTypeO, DTypeO, IdType>;
677	  size_t smem_size =
678	      max(sizeof(typename KTraits1::SharedStorage), sizeof(typename KTraits2::SharedStorage));
679	  smem_size = max(smem_size, ReductionKTraits::SMEM_SIZE);
680	
681	  // Launch persistent kernel
682	  auto kernel = PersistentKernelTemplate<BlockBatchPagedAttentionPersistent<KTraits1, Params>,
683	                                         BlockBatchPagedAttentionPersistent<KTraits2, Params>,
684	                                         BlockBatchReductionPersistent<ReductionKTraits>>;
685	  FLASHINFER_CUDA_CALL(
686	      cudaFuncSetAttribute(kernel, cudaFuncAttributeMaxDynamicSharedMemorySize, smem_size));
687	  dim3 nblks(num_blks_x, num_blks_y);
688	  dim3 nthrs(NUM_THREADS);
689	  void* args[] = {(void*)&params_1, (void*)&params_2};
690	  FLASHINFER_CUDA_CALL(
691	      cudaLaunchCooperativeKernel((void*)kernel, nblks, nthrs, args, smem_size, stream));
692	  return cudaSuccess;
693	}
